    const formData = new FormData();
    formData.append('photo', file);
    
    try {
        const response = await fetch(`http://localhost:5000/api/work-requests/${workId}/upload-photo`, {
            method: 'POST',
            headers: {
                'username': currentUser.username
            },
            body: formData
        });
        
        if (response.ok) {
            alert(`✅ Photo uploaded to WORK_${workId} folder!`);
            fetchRequests(currentUser.id);
        } else {
            const error = await response.json();
            alert(`❌ Upload failed: ${error.error || 'Unknown error'}`);
        }
    } catch (error) {
        console.error("Error:", error);
        alert("❌ Server Error. Check backend.");
    } finally {
        setUploading(false);
    }
};

    // 🎤 Upload Audio
    const uploadAudio = async (workId, audioBlob) => {
    setUploading(true);
    const formData = new FormData();
    
    const audioFile = new File([audioBlob], `audio_${Date.now()}.webm`, { type: 'audio/webm' });
    formData.append('audio', audioFile);
    
    try {
        const response = await fetch(`http://localhost:5000/api/work-requests/${workId}/upload-audio`, {
            method: 'POST',
            headers: {
                'username': currentUser.username
            },
            body: formData
        });
        
        if (response.ok) {
            alert(`✅ Audio uploaded to WORK_${workId} folder!`);
            setRecordingId(null);
            setIsRecording(false);
            fetchRequests(currentUser.id);
        } else {
            const error = await response.json();
            alert(`❌ Upload failed: ${error.error || 'Unknown error'}`);
        }
    } catch (error) {
        console.error("Upload error:", error);
        alert("❌ Server Error. Check console for details.");
    } finally {
        setUploading(false);
    }
};

